update rider_apply
user_id = #{userId}, name = #{name}, sex = #{sex}, college = #{college}, major_class = #{majorClass}, student_card = #{studentCard}, health_card = #{healthCard}, status = #{status},
where id = #{id}

mapper.select:
select  from rider_apply

    and user_id = #{userId}
    and name like concat('%', #{name}, '%')
    and sex = #{sex}
    and college like concat('%', #{college}, '%')
    and status = #{status}

order by create_time desc
